import{_ as a,c as i,a as t,o as m}from"./app-CEcM0piI.js";const l={};function c(k,e){return m(),i("div",null,e[0]||(e[0]=[t("<p>CMake 是一个项目构建工具，并且是跨平台的。关于项目构建我们所熟知的还有Makefile（通过 make 命令进行项目的构建），大多是IDE软件都集成了make，比如：VS 的 nmake、linux 下的 GNU make、Qt 的 qmake等，如果自己动手写 makefile，会发现，makefile 通常依赖于当前的编译平台，而且编写 makefile 的工作量比较大，解决依赖关系时也容易出错。</p><p>而 CMake 恰好能解决上述问题， 其允许开发者指定整个工程的编译流程，在根据编译平台，<code>自动生成本地化的Makefile和工程文件</code>，最后用户只需<code>make</code>编译即可，所以可以把CMake看成一款自动生成 Makefile的工具，其编译流程如下图： ![[Pasted image 20240304194526.png]]</p><ul><li>蓝色虚线表示使用<code>makefile</code>构建项目的过程</li><li>红色实线表示使用<code>cmake</code>构建项目的过程</li></ul><p>总结一下CMake的优点：</p><ul><li>跨平台</li><li>能够管理大型项目</li><li>简化编译构建过程和编译过程</li><li>可扩展：可以为 cmake 编写特定功能的模块，扩充 cmake 功能</li></ul>",5)]))}const n=a(l,[["render",c]]),p=JSON.parse('{"path":"/cpp/cmake/1/","title":"1 CMake概述","lang":"zh-CN","frontmatter":{"title":"1 CMake概述","createTime":"2025/04/05 12:12:26","permalink":"/cpp/cmake/1/"},"readingTime":{"minutes":1.01,"words":303},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/C++/cmake/1 CMake概述.md","headers":[]}');export{n as comp,p as data};
